package main

import (
	"encoding/json"
	"fmt"
	"strings"
)

type Event struct {
	Type    string `json:"type"`
	Message string `json:"message"`
}

func main() {
	stream := `{"type":"info","message":"Server started"}
{"type":"warn","message":"High memory usage"}
{"type":"error","message":"Connection failed"}`

	decoder := json.NewDecoder(strings.NewReader(stream))
	for decoder.More() {
		var e Event
		if err := decoder.Decode(&e); err != nil {
			fmt.Println("Decode error:", err)
			break
		}
		fmt.Printf("[%s] %s\n", e.Type, e.Message)
	}
}

package main

import (
	"encoding/json"
	"fmt"
)

type User struct {
	Name     string
	Email    string
	Password string
}

func (u User) MarshalJSON() ([]byte, error) {
	type Alias struct {
		Name     string `json:"name"`
		Email    string `json:"email"`
		Password string `json:"password"`
	}
	return json.Marshal(Alias{
		Name:     u.Name,
		Email:    u.Email,
		Password: "***", // TODO: change to "[hidden]"
	})
}

func main() {
	u := User{Name: "Alex", Email: "alex@example.com", Password: "supersecret123"}
	data, _ := json.Marshal(u)
	fmt.Println(string(data))
}

